<?php
$configPath = __DIR__ . '/config.php';
if (!file_exists($configPath)) { die('Falta dashboard/config.php'); }
$config = require $configPath;
$dsn = sprintf('mysql:host=%s;port=%s;dbname=%s;charset=%s', $config['db_host'], $config['db_port'], $config['db_name'], $config['charset']);
$pdo = new PDO($dsn, $config['db_user'], $config['db_pass'], [PDO::ATTR_ERRMODE=>PDO::ERRMODE_EXCEPTION, PDO::ATTR_DEFAULT_FETCH_MODE=>PDO::FETCH_ASSOC]);
$pdo->exec('SET NAMES utf8mb4 COLLATE utf8mb4_unicode_ci');
$areaCodes = range('A', 'P');
$areaEnum = "'" . implode("','", $areaCodes) . "'";
$pdo->exec("INSERT IGNORE INTO unit_types (name, description, created_at, updated_at) VALUES ('area_policial','Area policial',NOW(),NOW())");
$pdo->exec("CREATE TABLE IF NOT EXISTS moi_area_letter_assignments (organizational_unit_id BIGINT UNSIGNED PRIMARY KEY, area_code ENUM($areaEnum) NOT NULL, area_unit_id BIGINT UNSIGNED NULL, direction_unit_id BIGINT UNSIGNED NULL, zone_unit_id BIGINT UNSIGNED NOT NULL, notes VARCHAR(255) NULL, created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX idx_area_letter (area_code), INDEX idx_area_unit (area_unit_id), INDEX idx_area_zone (zone_unit_id), INDEX idx_area_direction (direction_unit_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci");
try { $pdo->exec("ALTER TABLE moi_area_letter_assignments MODIFY area_code ENUM($areaEnum) NOT NULL"); } catch (Throwable $e) {}
try { $pdo->exec("ALTER TABLE moi_area_letter_assignments ADD COLUMN area_unit_id BIGINT UNSIGNED NULL AFTER area_code"); } catch (Throwable $e) {}
$pdo->exec("CREATE TABLE IF NOT EXISTS moi_area_assignment_audit (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, organizational_unit_id BIGINT UNSIGNED NOT NULL, legacy_table VARCHAR(80) NULL, legacy_id VARCHAR(80) NULL, nombre_antes VARCHAR(255) NULL, nombre_despues VARCHAR(255) NULL, area_code ENUM($areaEnum) NULL, area_unit_id BIGINT UNSIGNED NULL, area_name VARCHAR(150) NULL, direction_unit_id BIGINT UNSIGNED NULL, direction_name VARCHAR(220) NULL, zone_unit_id BIGINT UNSIGNED NULL, zone_name VARCHAR(220) NULL, accion VARCHAR(80) NOT NULL DEFAULT 'asignar_area', notes VARCHAR(255) NULL, created_by VARCHAR(100) NULL DEFAULT 'dashboard', created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP, INDEX idx_audit_unit (organizational_unit_id), INDEX idx_audit_created (created_at), INDEX idx_audit_area (area_code), INDEX idx_audit_zone (zone_unit_id), INDEX idx_audit_direction (direction_unit_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci");
try { $pdo->exec("ALTER TABLE moi_area_assignment_audit MODIFY area_code ENUM($areaEnum) NULL"); } catch (Throwable $e) {}
function h($v){ return htmlspecialchars((string)$v, ENT_QUOTES, 'UTF-8'); }
function q($pdo,$sql,$p=[]){ $s=$pdo->prepare($sql); $s->execute($p); return $s->fetchAll(); }
function one($pdo,$sql,$p=[]){ $r=q($pdo,$sql,$p); return $r[0] ?? null; }
function x($pdo,$sql,$p=[]){ $s=$pdo->prepare($sql); $s->execute($p); }
function area_default($name){ return preg_match('/AREA\s*([A-P])\b/i', (string)$name, $m) ? strtoupper($m[1]) : 'A'; }
function csv_out($value){ return mb_convert_encoding((string)$value, 'UTF-8', 'UTF-8'); }
function ensure_area_unit($pdo, $zoneUnitId, $zoneNumber, $zoneLabel, $areaCode){
    $legacyId = 'Z'.str_pad((string)$zoneNumber,2,'0',STR_PAD_LEFT).'-AREA-'.$areaCode;
    $found = one($pdo, "SELECT id FROM organizational_units WHERE BINARY legacy_table=BINARY 'MOI_CABECERA_AREA' AND BINARY legacy_id=BINARY :legacy_id", ['legacy_id'=>$legacyId]);
    if ($found) { return (int)$found['id']; }
    $ut = one($pdo, "SELECT id FROM unit_types WHERE name='area_policial' LIMIT 1");
    $code = 'Z'.str_pad((string)$zoneNumber,2,'0',STR_PAD_LEFT).'-AREA-'.$areaCode;
    $name = 'Area '.$areaCode;
    x($pdo, "INSERT INTO organizational_units (parent_id, unit_type_id, code, name, short_name, level, is_operational, is_administrative, status, legacy_table, legacy_id, created_at, updated_at) VALUES (:parent_id,:unit_type_id,:code,:name,:short_name,4,1,1,'active','MOI_CABECERA_AREA',:legacy_id,NOW(),NOW())", ['parent_id'=>$zoneUnitId,'unit_type_id'=>$ut['id'],'code'=>$code,'name'=>$name,'short_name'=>$name,'legacy_id'=>$legacyId]);
    $areaId = (int)$pdo->lastInsertId();
    try { x($pdo, "UPDATE organizational_units SET moi_code=:code, moi_level=4, command_structure='mando_directo', command_relationship='tactico', territorial_scope='area', is_decision_center=1, is_operational_executor=1, valid_from=CURRENT_DATE, lifecycle_status='vigente', structure_source='moi_65_16', legacy_frozen=1, lifecycle_notes=:note WHERE id=:id", ['code'=>$code,'note'=>'Cabecera real de '.$name.' dentro de '.$zoneLabel,'id'=>$areaId]); } catch (Throwable $e) {}
    try { x($pdo, "INSERT INTO organizational_unit_relationships (source_unit_id,target_unit_id,relationship_type,valid_from,status,notes,created_at,updated_at) SELECT :area,:zona,'jerarquica',CURRENT_DATE,'active','Area cabecera pertenece a zona',NOW(),NOW() WHERE NOT EXISTS (SELECT 1 FROM organizational_unit_relationships WHERE source_unit_id=:area2 AND target_unit_id=:zona2 AND relationship_type='jerarquica' AND status='active')", ['area'=>$areaId,'zona'=>$zoneUnitId,'area2'=>$areaId,'zona2'=>$zoneUnitId]); } catch (Throwable $e) {}
    return $areaId;
}
if (($_GET['descargar'] ?? '') === 'respaldo') {
    $rows = q($pdo, "SELECT id, created_at, organizational_unit_id, legacy_table, legacy_id, nombre_antes, nombre_despues, area_code, area_name, direction_name, zone_name, notes, created_by FROM moi_area_assignment_audit ORDER BY id DESC");
    header('Content-Type: text/csv; charset=utf-8');
    header('Content-Disposition: attachment; filename=respaldo_asignacion_areas.csv');
    $out = fopen('php://output', 'w');
    fputcsv($out, ['ID','Fecha','Unidad ID','Legacy tabla','Legacy ID','Nombre antes','Nombre despues','Area','Area real','Direccion','Zona','Nota','Usuario']);
    foreach ($rows as $r) { fputcsv($out, array_map('csv_out', $r)); }
    fclose($out);
    exit;
}
$msg = isset($_GET['ok']) ? 'Unidad aprobada/asignada. Quedo respaldado el nombre antes y despues.' : '';
$err = '';
$zonaJoin = "BINARY cab.legacy_table = BINARY 'MOI_CABECERA_ZONA' AND CAST(cab.legacy_id AS UNSIGNED) = z.zone_number";
$dirJoin = "BINARY dcab.legacy_table = BINARY 'MOI_CABECERA_DIRECCION' AND CAST(dcab.legacy_id AS UNSIGNED) = d.direction_number";
$zonas = q($pdo, "SELECT z.id,z.zone_number,z.zone_label,z.normalized_name,cab.id AS cabecera_unit_id FROM moi_zonas_cabecera_vigentes z LEFT JOIN organizational_units cab ON $zonaJoin WHERE z.lifecycle_status='vigente' ORDER BY z.zone_number");
$direcciones = q($pdo, "SELECT d.id,d.direction_number,d.direction_label,dcab.id AS cabecera_unit_id FROM moi_direcciones_cabecera_vigentes d LEFT JOIN organizational_units dcab ON $dirJoin WHERE d.lifecycle_status='vigente' ORDER BY d.direction_number");
$zonaId = (int)($_GET['zona_id'] ?? ($_POST['zona_id'] ?? ($zonas[0]['id'] ?? 0)));
$zona = one($pdo, "SELECT z.id,z.zone_number,z.zone_label,z.normalized_name,cab.id AS cabecera_unit_id FROM moi_zonas_cabecera_vigentes z LEFT JOIN organizational_units cab ON $zonaJoin WHERE z.id=:id", ['id'=>$zonaId]);
try {
    if ($_SERVER['REQUEST_METHOD']==='POST' && ($_POST['accion'] ?? '')==='asignar') {
        $unitId=(int)($_POST['unit_id'] ?? 0);
        $zonaTargetId=(int)($_POST['zona_target_id'] ?? 0);
        $direccionTargetId=(int)($_POST['direccion_target_id'] ?? 0);
        $areaCode=strtoupper(trim($_POST['area_code'] ?? 'A'));
        if (!in_array($areaCode, $areaCodes, true)) { $areaCode = 'A'; }
        $nombre=trim($_POST['nombre'] ?? '');
        $unitBefore = one($pdo, "SELECT id, name, legacy_table, legacy_id FROM organizational_units WHERE id=:id", ['id'=>$unitId]);
        if (!$unitBefore) { throw new RuntimeException('Unidad no encontrada.'); }
        $nombreAntes = $unitBefore['name'];
        $nombreDespues = $nombre !== '' ? $nombre : $nombreAntes;
        $zonaTarget=one($pdo, "SELECT z.id,z.zone_number,z.zone_label,cab.id AS cabecera_unit_id FROM moi_zonas_cabecera_vigentes z LEFT JOIN organizational_units cab ON $zonaJoin WHERE z.id=:id", ['id'=>$zonaTargetId]);
        if (!$zonaTarget || !$zonaTarget['cabecera_unit_id']) { throw new RuntimeException('La zona seleccionada no tiene cabecera canonica.'); }
        $areaUnitId = ensure_area_unit($pdo, (int)$zonaTarget['cabecera_unit_id'], (int)$zonaTarget['zone_number'], $zonaTarget['zone_label'], $areaCode);
        $areaName = 'Area '.$areaCode;
        $direccionTarget = null;
        if ($direccionTargetId > 0) {
            $direccionTarget=one($pdo, "SELECT d.id,d.direction_label,dcab.id AS cabecera_unit_id FROM moi_direcciones_cabecera_vigentes d LEFT JOIN organizational_units dcab ON $dirJoin WHERE d.id=:id", ['id'=>$direccionTargetId]);
            if (!$direccionTarget || !$direccionTarget['cabecera_unit_id']) { throw new RuntimeException('La direccion seleccionada no tiene cabecera canonica.'); }
        }
        $parentId = $direccionTarget ? $direccionTarget['cabecera_unit_id'] : $areaUnitId;
        $directionUnitId = $direccionTarget ? $direccionTarget['cabecera_unit_id'] : null;
        $directionName = $direccionTarget ? $direccionTarget['direction_label'] : null;
        $notaBase = $direccionTarget ? 'Pertenece a '.$direccionTarget['direction_label'].'; area '.$areaCode.'; ubicada en '.$zonaTarget['zone_label'] : 'Pertenece al Area '.$areaCode.' de '.$zonaTarget['zone_label'];
        $nota = 'Area '.$areaCode.' - '.$notaBase;
        x($pdo, 'UPDATE organizational_units SET name=:n, short_name=LEFT(:n2,100), parent_id=:p, lifecycle_notes=:nota, updated_at=NOW() WHERE id=:id', ['n'=>$nombreDespues,'n2'=>$nombreDespues,'p'=>$parentId,'nota'=>$nota,'id'=>$unitId]);
        x($pdo, "INSERT INTO organizational_unit_relationships (source_unit_id,target_unit_id,relationship_type,valid_from,status,notes,created_at,updated_at) SELECT :h,:p,'jerarquica',CURRENT_DATE,'active',:nota,NOW(),NOW() WHERE NOT EXISTS (SELECT 1 FROM organizational_unit_relationships WHERE source_unit_id=:h2 AND target_unit_id=:p2 AND relationship_type='jerarquica' AND status='active')", ['h'=>$unitId,'p'=>$parentId,'nota'=>$nota,'h2'=>$unitId,'p2'=>$parentId]);
        x($pdo, "INSERT INTO organizational_unit_relationships (source_unit_id,target_unit_id,relationship_type,valid_from,status,notes,created_at,updated_at) SELECT :h,:area,'ubicacion_fisica',CURRENT_DATE,'active',:nota,NOW(),NOW() WHERE NOT EXISTS (SELECT 1 FROM organizational_unit_relationships WHERE source_unit_id=:h2 AND target_unit_id=:area2 AND relationship_type='ubicacion_fisica' AND status='active')", ['h'=>$unitId,'area'=>$areaUnitId,'nota'=>$nota,'h2'=>$unitId,'area2'=>$areaUnitId]);
        x($pdo, "INSERT INTO organizational_unit_relationships (source_unit_id,target_unit_id,relationship_type,valid_from,status,notes,created_at,updated_at) SELECT :h,:z,'ubicacion_fisica',CURRENT_DATE,'active',:nota,NOW(),NOW() WHERE NOT EXISTS (SELECT 1 FROM organizational_unit_relationships WHERE source_unit_id=:h2 AND target_unit_id=:z2 AND relationship_type='ubicacion_fisica' AND status='active')", ['h'=>$unitId,'z'=>$zonaTarget['cabecera_unit_id'],'nota'=>$nota,'h2'=>$unitId,'z2'=>$zonaTarget['cabecera_unit_id']]);
        x($pdo, "INSERT INTO moi_area_letter_assignments (organizational_unit_id, area_code, area_unit_id, direction_unit_id, zone_unit_id, notes) VALUES (:u,:a,:area,:d,:z,:n) ON DUPLICATE KEY UPDATE area_code=VALUES(area_code), area_unit_id=VALUES(area_unit_id), direction_unit_id=VALUES(direction_unit_id), zone_unit_id=VALUES(zone_unit_id), notes=VALUES(notes), updated_at=NOW()", ['u'=>$unitId,'a'=>$areaCode,'area'=>$areaUnitId,'d'=>$directionUnitId,'z'=>$zonaTarget['cabecera_unit_id'],'n'=>$nota]);
        x($pdo, "INSERT INTO moi_area_assignment_audit (organizational_unit_id, legacy_table, legacy_id, nombre_antes, nombre_despues, area_code, area_unit_id, area_name, direction_unit_id, direction_name, zone_unit_id, zone_name, notes, created_by) VALUES (:u,:lt,:li,:antes,:despues,:area_code,:area_unit_id,:area_name,:direction_unit_id,:direction_name,:zone_unit_id,:zone_name,:notes,'dashboard')", ['u'=>$unitId,'lt'=>$unitBefore['legacy_table'],'li'=>$unitBefore['legacy_id'],'antes'=>$nombreAntes,'despues'=>$nombreDespues,'area_code'=>$areaCode,'area_unit_id'=>$areaUnitId,'area_name'=>$areaName,'direction_unit_id'=>$directionUnitId,'direction_name'=>$directionName,'zone_unit_id'=>$zonaTarget['cabecera_unit_id'],'zone_name'=>$zonaTarget['zone_label'],'notes'=>$nota]);
        header('Location: asignar_areas.php?zona_id='.(int)$zonaId.'&ok=1'); exit;
    }
} catch(Throwable $e){ $err=$e->getMessage(); }
$buscar=trim($_GET['buscar'] ?? '');
$clave=$buscar!=='' ? strtoupper($buscar) : ($zona['normalized_name'] ?? '');
$extra='';
if (($zona['zone_number'] ?? 0)==8) { $extra=" AND UPPER(ou.name COLLATE utf8mb4_unicode_ci) NOT LIKE '%PANAMA OESTE%'"; }
$excluir = "AND BINARY ou.legacy_table <> BINARY 'MOI_CABECERA_AREA' AND NOT EXISTS (SELECT 1 FROM organizational_units c WHERE c.id=ou.parent_id AND BINARY c.legacy_table IN ('MOI_CABECERA_ZONA','MOI_CABECERA_DIRECCION','MOI_CABECERA_AREA')) AND NOT EXISTS (SELECT 1 FROM organizational_unit_relationships r JOIN organizational_units zc ON zc.id=r.target_unit_id WHERE r.source_unit_id=ou.id AND r.status='active' AND BINARY zc.legacy_table IN ('MOI_CABECERA_ZONA','MOI_CABECERA_AREA'))";
$candidatos=$zona ? q($pdo, "SELECT ou.id,ou.name,ou.legacy_table,ou.legacy_id,ut.name AS tipo,parent.name AS superior FROM organizational_units ou LEFT JOIN unit_types ut ON ut.id=ou.unit_type_id LEFT JOIN organizational_units parent ON parent.id=ou.parent_id WHERE ou.lifecycle_status='vigente' $excluir AND UPPER(ou.name COLLATE utf8mb4_unicode_ci) LIKE :pat $extra ORDER BY ou.name LIMIT 200", ['pat'=>'%'.$clave.'%']) : [];
$asignadas=$zona ? q($pdo, "SELECT DISTINCT ou.id,ou.name,ou.legacy_table,ou.legacy_id,ut.name AS tipo,parent.name AS superior,aa.area_code, area.name AS area_name, aud.nombre_antes, aud.nombre_despues FROM organizational_units ou LEFT JOIN unit_types ut ON ut.id=ou.unit_type_id LEFT JOIN organizational_units parent ON parent.id=ou.parent_id LEFT JOIN moi_area_letter_assignments aa ON aa.organizational_unit_id=ou.id LEFT JOIN organizational_units area ON area.id=aa.area_unit_id LEFT JOIN organizational_unit_relationships rz ON rz.source_unit_id=ou.id AND rz.status='active' LEFT JOIN (SELECT a.* FROM moi_area_assignment_audit a JOIN (SELECT organizational_unit_id, MAX(id) AS max_id FROM moi_area_assignment_audit GROUP BY organizational_unit_id) m ON m.max_id=a.id) aud ON aud.organizational_unit_id=ou.id WHERE (aa.zone_unit_id=:cab OR ou.parent_id=:cab2 OR rz.target_unit_id=:cab3) ORDER BY aa.area_code, ou.name LIMIT 150", ['cab'=>$zona['cabecera_unit_id'] ?? 0,'cab2'=>$zona['cabecera_unit_id'] ?? 0,'cab3'=>$zona['cabecera_unit_id'] ?? 0]) : [];
$auditoria = q($pdo, "SELECT * FROM moi_area_assignment_audit ORDER BY id DESC LIMIT 30");
?>
<!doctype html><html lang="es"><head><meta charset="utf-8"><title>Asignar areas y respaldo</title><style>body{font-family:Arial;margin:0;background:#f4f6f8;color:#1f2937}header{background:#111827;color:white;padding:18px 28px}main{padding:20px}.layout{display:grid;grid-template-columns:330px 1fr;gap:18px}.card,section{background:white;border-radius:10px;padding:14px;box-shadow:0 1px 4px #0002;margin-bottom:16px}.cab a{display:block;padding:8px;border-bottom:1px solid #e5e7eb;color:#111827;text-decoration:none}.cab a.act{background:#e0f2fe;font-weight:bold}.top a{color:#d1d5db;margin-right:14px}.msg{background:#ecfdf5;border:1px solid #10b981;padding:10px;border-radius:8px}.err{background:#fef2f2;border:1px solid #ef4444;padding:10px;border-radius:8px}table{width:100%;border-collapse:collapse;font-size:13px}th,td{border-bottom:1px solid #e5e7eb;text-align:left;padding:7px;vertical-align:top}th{background:#f9fafb}input,select,button{padding:7px;border:1px solid #d1d5db;border-radius:6px}button,.btn{background:#047857;color:white;text-decoration:none;border-radius:6px;padding:8px;display:inline-block}.muted{font-size:12px;color:#6b7280}.wide{min-width:260px}</style></head><body><header><h1>Asignar unidad: direccion, zona, area real y respaldo</h1><p class="top"><a href="index.php">Dashboard</a><a href="asignar_zonas.php">Zonas</a><a href="asignar_direcciones.php">Direcciones</a><a href="asignar_unidades_direccion.php">Unidades de direccion</a></p></header><main><?php if($msg):?><p class="msg"><?=h($msg)?></p><?php endif;?><?php if($err):?><p class="err"><?=h($err)?></p><?php endif;?><p><a class="btn" href="?descargar=respaldo">Descargar respaldo CSV</a></p><div class="layout"><div class="card cab"><h2>Zona de ubicacion</h2><?php foreach($zonas as $z):?><a class="<?=((int)$z['id']===(int)($zona['id']??0))?'act':''?>" href="?zona_id=<?=h($z['id'])?>"><?=h($z['zone_number'])?> - <?=h($z['zone_label'])?></a><?php endforeach;?></div><div><section><h2>Ubicadas en <?=h($zona['zone_label'] ?? 'zona')?></h2><p class="muted">Areas disponibles A-P. Se guarda nombre antes, nombre despues, area real, direccion, zona y legacy.</p><form method="get"><input type="hidden" name="zona_id" value="<?=h($zona['id'] ?? '')?>"><input name="buscar" value="<?=h($buscar)?>" placeholder="Buscar palabra"><button>Buscar</button></form><p>Filtro usado: <?=h($clave)?></p></section><section><h2>Pendientes para aprobar/asignar</h2><table><thead><tr><th>Unidad encontrada</th><th>Superior actual</th><th>Editar / asignar</th></tr></thead><tbody><?php foreach($candidatos as $r): $areaSel=area_default($r['name']); ?><tr><td><b><?=h($r['name'])?></b><br><span class="muted"><?=h($r['tipo'])?> | <?=h($r['legacy_table'])?>: <?=h($r['legacy_id'])?></span></td><td><?=h($r['superior'] ?: 'Sin superior')?></td><td><form method="post"><input type="hidden" name="accion" value="asignar"><input type="hidden" name="zona_id" value="<?=h($zona['id'] ?? '')?>"><input type="hidden" name="unit_id" value="<?=h($r['id'])?>"><span class="muted">Nombre despues:</span><br><input name="nombre" value="<?=h($r['name'])?>" size="30"><br><span class="muted">Area real dentro de la zona:</span><br><select name="area_code"><?php foreach($areaCodes as $a): ?><option value="<?=h($a)?>" <?=$areaSel===$a?'selected':''?>>Area <?=h($a)?></option><?php endforeach; ?></select><br><span class="muted">Pertenece a direccion:</span><br><select class="wide" name="direccion_target_id"><option value="0">No aplica / pertenece al area de zona</option><?php foreach($direcciones as $d):?><option value="<?=h($d['id'])?>"><?=h($d['direction_number'])?> - <?=h($d['direction_label'])?></option><?php endforeach;?></select><br><span class="muted">Ubicada en zona:</span><br><select class="wide" name="zona_target_id"><?php foreach($zonas as $z):?><option value="<?=h($z['id'])?>" <?=((int)$z['id']===(int)($zona['id']??0))?'selected':''?>><?=h($z['zone_number'])?> - <?=h($z['zone_label'])?></option><?php endforeach;?></select><br><button>Aprobar / asignar</button></form></td></tr><?php endforeach;?></tbody></table></section><section><h2>Ya asignadas/ubicadas en esta zona</h2><table><thead><tr><th>Area real</th><th>Nombre antes</th><th>Nombre despues</th><th>Tipo</th><th>Superior principal</th><th>Legacy</th></tr></thead><tbody><?php foreach($asignadas as $r):?><tr><td><?=h($r['area_name'] ?: ($r['area_code'] ? 'Area '.$r['area_code'] : ''))?></td><td><?=h($r['nombre_antes'] ?: '')?></td><td><?=h($r['nombre_despues'] ?: $r['name'])?></td><td><?=h($r['tipo'])?></td><td><?=h($r['superior'])?></td><td><?=h($r['legacy_table'])?>: <?=h($r['legacy_id'])?></td></tr><?php endforeach;?></tbody></table></section><section><h2>Respaldo reciente del trabajo</h2><table><thead><tr><th>Fecha</th><th>Nombre antes</th><th>Nombre despues</th><th>Area</th><th>Direccion</th><th>Zona</th><th>Legacy</th></tr></thead><tbody><?php foreach($auditoria as $a):?><tr><td><?=h($a['created_at'])?></td><td><?=h($a['nombre_antes'])?></td><td><?=h($a['nombre_despues'])?></td><td><?=h($a['area_name'])?></td><td><?=h($a['direction_name'])?></td><td><?=h($a['zone_name'])?></td><td><?=h($a['legacy_table'])?>: <?=h($a['legacy_id'])?></td></tr><?php endforeach;?></tbody></table></section></div></div></main></body></html>
